 1	import * as React from 'react';
 2	
 3	import { useIsAdmin } from '@kubevirt-utils/hooks/useIsAdmin';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Popover, Stack, StackItem, Title } from '@patternfly/react-core';
 6	
 7	import useHyperConvergedMigrations from './hooks/useHyperConvergedMigrations';
 8	
 9	const MigrationsLimitionsPopover: React.FC = () => {
10	  const { t } = useKubevirtTranslation();
11	  const migrations = useHyperConvergedMigrations();
12	  const isAdmin = useIsAdmin();
13	
14	  if (!isAdmin) return null;
15	
16	  return (
17	    <Popover
18	      bodyContent={
19	        <Stack hasGutter>
20	          <Title headingLevel="h3">{t('Live migrations settings')}</Title>
21	          <StackItem>
22	            <b>{t('Max. running migrations per cluster')}</b>
23	            <div>{migrations?.parallelMigrationsPerCluster}</div>
24	          </StackItem>
25	          <StackItem>
26	            <b>{t('Max. running migrations per node')}</b>
27	            <div>{migrations?.parallelOutboundMigrationsPerNode}</div>
28	          </StackItem>
29	        </Stack>
30	      }
31	    >
32	      <a onClick={(e) => e.preventDefault()}>{t('Limitations')}</a>
33	    </Popover>
34	  );
35	};
36	
37	export default MigrationsLimitionsPopover;

